var SOS_DATA = {"modules":[{"id":"cliente_comprador","label":"Cliente comprador","questions":["q01","q02","q03"]},{"id":"posicionamento","label":"Posicionamento","questions":["q04","q05","q06"]},{"id":"oferta_principal","label":"Oferta principal","questions":["q07","q08","q09"]},{"id":"preco_valor","label":"Preço e valor percebido","questions":["q10","q11","q12"]},{"id":"conteudo_hooks","label":"Conteúdo e hooks","questions":["q13","q14","q15"]},{"id":"alcance_divulgacao","label":"Alcance e divulgação","questions":["q16","q17","q18"]},{"id":"prova_confianca","label":"Prova e confiança","questions":["q19","q20","q21"]},{"id":"caminho_compra","label":"Caminho de compra","questions":["q22","q23","q24"]},{"id":"fecho_acompanhamento","label":"Fecho e acompanhamento","questions":["q25","q26","q27"]},{"id":"ritmo_campanhas","label":"Ritmo e campanhas","questions":["q28","q29","q30"]}],"categories":[{"id":"direcao","label":"Direção da loja","modules":["cliente_comprador","posicionamento"]},{"id":"oferta_valor","label":"Oferta e valor","modules":["oferta_principal","preco_valor"]},{"id":"conteudo_visibilidade","label":"Conteúdo e visibilidade","modules":["conteudo_hooks","alcance_divulgacao"]},{"id":"confianca_relacao","label":"Confiança e relação","modules":["prova_confianca"]},{"id":"compra_venda","label":"Compra e venda","modules":["caminho_compra","fecho_acompanhamento"]},{"id":"planeamento","label":"Planeamento comercial","modules":["ritmo_campanhas"]}],"totalBands":[{"min":0,"max":29,"id":"sem_base_estavel","label":"Sem base estável"},{"min":30,"max":49,"id":"trabalho_disperso","label":"Trabalho disperso"},{"min":50,"max":64,"id":"base_incompleta","label":"Base incompleta"},{"min":65,"max":79,"id":"estrutura_funcional","label":"Estrutura funcional"},{"min":80,"max":100,"id":"estrutura_solida","label":"Estrutura sólida"}],"moduleBands":[{"min":0,"max":39,"id":"bloqueio_direto","label":"Bloqueio direto"},{"min":40,"max":59,"id":"base_instavel","label":"Base instável"},{"min":60,"max":74,"id":"perde_oportunidades","label":"Funciona, mas perde oportunidades"},{"min":75,"max":89,"id":"area_forte","label":"Área forte"},{"min":90,"max":100,"id":"area_consolidada","label":"Área consolidada"}],"priority":{"eligible_below":60,"minimum_weak_answers":2,"weak_answer_max":2,"root_cause_max_distance":10,"tie_max_distance":5,"max_priorities_shown":2,"fallback_order":["cliente_comprador","posicionamento","oferta_principal","preco_valor","conteudo_hooks","alcance_divulgacao","prova_confianca","caminho_compra","fecho_acompanhamento","ritmo_campanhas"],"dependencies":{"cliente_comprador":["posicionamento","oferta_principal","conteudo_hooks"],"posicionamento":["oferta_principal","conteudo_hooks","alcance_divulgacao"],"oferta_principal":["preco_valor","conteudo_hooks","caminho_compra"],"preco_valor":["fecho_acompanhamento"],"conteudo_hooks":["alcance_divulgacao","prova_confianca"],"alcance_divulgacao":[],"prova_confianca":["caminho_compra","fecho_acompanhamento"],"caminho_compra":["fecho_acompanhamento"],"fecho_acompanhamento":[],"ritmo_campanhas":[]}},"baseReadings":{"cliente_comprador":{"bloqueio_direto":"A loja está a tentar falar com pessoas demasiado diferentes. Sem saber quem compra, quem recebe o produto e em que situação a procura começa, torna-se difícil escolher produtos, escrever conteúdos ou preparar uma oferta que pareça feita para alguém concreto.","base_instavel":"Já tens uma ideia de quem pode comprar, mas essa ideia ainda muda conforme o produto ou a publicação. Em alguns momentos a comunicação acerta; noutros volta a falar para “toda a gente” e perde força.","perde_oportunidades":"Existe uma direção sobre a cliente e os momentos de compra, mas nem sempre essa informação entra nas decisões da loja. Alguns produtos e conteúdos estão bem ligados à pessoa certa; outros continuam apresentados sem contexto suficiente.","area_forte":"Sabes quem compra, reconheces situações reais de procura e usas essa informação com regularidade. O próximo ganho está em observar diferenças entre tipos de cliente e perceber quais trazem melhores encomendas.","area_consolidada":"A cliente compradora está clara, as situações de compra orientam a loja e as decisões são corrigidas com base em sinais reais. Esta área não precisa de ser tratada como uma urgência."},"posicionamento":{"bloqueio_direto":"Quem entra na loja encontra produtos, mas não percebe rapidamente que tipo de compra consegue resolver ali nem por que razão deve continuar. A loja pode estar bem apresentada e, mesmo assim, parecer igual a muitas alternativas.","base_instavel":"Existe uma ideia sobre aquilo que distingue a loja, mas essa diferença ainda aparece de forma irregular. A bio pode dizer uma coisa, os produtos outra e as publicações mudar de direção conforme a semana.","perde_oportunidades":"A loja já comunica uma direção reconhecível, embora alguns produtos ou mensagens ainda não reforcem essa escolha. A cliente percebe a oferta principal, mas nem sempre encontra uma razão concreta para preferir esta loja.","area_forte":"A oferta e a diferença da loja são percebidas com facilidade. O próximo passo é tornar essa posição mais consistente nas campanhas, novidades e produtos secundários.","area_consolidada":"A loja é reconhecível, atrai pedidos alinhados com aquilo que pretende vender e apresenta uma razão concreta para ser escolhida. Não existe motivo para vender posicionamento como uma necessidade imediata."},"oferta_principal":{"bloqueio_direto":"A loja mostra demasiadas opções sem indicar aquilo que merece prioridade. A cliente tem de comparar tudo sozinha e a própria lojista divide o esforço por produtos que não têm o mesmo valor comercial.","base_instavel":"Existem produtos com potencial, mas a prioridade muda com frequência ou depende do que acabou de ser produzido. A loja ainda não conduz a cliente para uma entrada clara.","perde_oportunidades":"A oferta principal já é reconhecível, mas as diferenças entre opções, níveis ou combinações ainda podem criar dúvida. Existe direção, embora alguns produtos continuem a competir pela mesma atenção.","area_forte":"A loja sabe o que quer vender e facilita a escolha entre as opções principais. O próximo ganho está em melhorar combinações, produtos complementares e repetição daquilo que já funciona.","area_consolidada":"Os produtos prioritários estão definidos com base em procura, capacidade e margem. A cliente percebe por onde começar e a loja consegue concentrar divulgação e produção."},"preco_valor":{"bloqueio_direto":"O preço está a ser definido ou apresentado sem mostrar tudo aquilo que precisa de pagar e justificar. A cliente vê um número antes de perceber materiais, tempo, escolha, segurança ou resultado, e a loja fica vulnerável a descontos e comparações injustas.","base_instavel":"Alguns custos e argumentos de valor já são considerados, mas existem falhas entre produtos ou conversas. A mesma loja pode explicar muito bem uma peça e apresentar outra apenas com fotografia e preço.","perde_oportunidades":"Os preços têm uma base e o valor é comunicado na maioria das situações. Ainda assim, algumas opções, condições ou respostas deixam a cliente sem contexto suficiente para comparar corretamente.","area_forte":"A loja conhece os custos, protege a margem e ajuda a cliente a perceber aquilo que recebe. O próximo passo é testar apresentações, conjuntos e opções que aumentem o valor médio sem depender de desconto.","area_consolidada":"Preço, margem, apresentação e conversa estão ligados. A cliente encontra contexto para decidir e a loja não precisa de tratar esta área como urgência."},"conteudo_hooks":{"bloqueio_direto":"O conteúdo mostra produtos, mas ainda não ajuda a pessoa certa a reconhecer uma situação, uma necessidade ou um motivo para continuar. Publicar exige esforço, mas cada publicação funciona como uma peça isolada.","base_instavel":"Já existem conteúdos com boas entradas, contexto e ação, mas isso não acontece com regularidade. A comunicação depende da inspiração e os resultados são difíceis de repetir.","perde_oportunidades":"A loja consegue ligar produto e situação na maioria dos conteúdos. Algumas publicações continuam demasiado descritivas ou terminam sem mostrar à cliente o que deve fazer a seguir.","area_forte":"O conteúdo chama a atenção certa, mostra o produto em contexto e conduz a uma ação. O próximo ganho está em testar formatos e repetir estruturas que já geraram sinais concretos.","area_consolidada":"Produto, pessoa, momento e ação aparecem ligados com consistência. A loja sabe reconhecer os conteúdos que funcionam e não precisa de comprar este módulo como correção urgente."},"alcance_divulgacao":{"bloqueio_direto":"A loja depende quase apenas das pessoas que já a conhecem. Quando as vendas abrandam, experimenta uma divulgação isolada, sem tempo ou repetição suficiente para perceber se funciona.","base_instavel":"Existem tentativas de chegar a pessoas novas, mas os canais, mensagens ou ofertas mudam antes de produzir uma leitura útil. A divulgação acontece, porém ainda não forma um processo repetível.","perde_oportunidades":"A loja já tem formas de ser descoberta e reconhece parte das origens dos pedidos. Falta consistência para comparar resultados e concentrar esforço nas fontes mais adequadas.","area_forte":"A divulgação chega a pessoas novas com regularidade e a loja consegue identificar os canais que trazem interesse. O próximo passo é melhorar a qualidade dos pedidos, não apenas a quantidade de visitas.","area_consolidada":"A descoberta da loja não depende da sorte de uma publicação. Existem ações repetíveis, fontes identificadas e decisões apoiadas em resultados."},"prova_confianca":{"bloqueio_direto":"A cliente precisa de confiar antes de pagar, mas ainda encontra poucas provas do produto real, da experiência de encomenda ou das condições. O receio não significa falta de interesse; pode significar falta de segurança.","base_instavel":"Já existem fotografias, opiniões ou informações úteis, mas estão incompletas, antigas ou espalhadas. A cliente encontra algumas respostas e continua obrigada a perguntar pelas restantes.","perde_oportunidades":"A loja transmite confiança na maioria das situações, embora alguns produtos ou tipos de encomenda ainda não tenham prova, contexto ou condições suficientemente visíveis.","area_forte":"Produtos reais, experiências de clientes e condições de compra estão presentes. O próximo ganho está em organizar estas provas por produto e situação, facilitando a decisão.","area_consolidada":"A cliente encontra provas recentes, contexto e condições antes de pagar. A confiança não depende apenas da simpatia ou da conversa privada."},"caminho_compra":{"bloqueio_direto":"A cliente consegue interessar-se, mas encontra obstáculos para escolher e encomendar. Informações essenciais estão ausentes ou espalhadas e cada pedido começa com várias perguntas que poderiam estar resolvidas.","base_instavel":"Já existe uma forma de encomendar, mas muda conforme o produto, o canal ou a pessoa que pergunta. Algumas clientes avançam; outras param quando precisam de reunir demasiada informação.","perde_oportunidades":"O percurso está montado e permite concluir encomendas, embora existam passos repetidos, dúvidas previsíveis ou dados que continuam a chegar incompletos.","area_forte":"A cliente percebe como escolher e a loja segue etapas consistentes. O próximo ganho está em reduzir mensagens desnecessárias e melhorar a confirmação antes de produzir ou enviar.","area_consolidada":"Informação, escolha, pedido e confirmação formam um percurso claro. A loja consegue receber encomendas completas sem depender de improvisação."},"fecho_acompanhamento":{"bloqueio_direto":"As conversas começam, mas não são conduzidas até uma decisão. O preço ou a disponibilidade são enviados sem um passo seguinte, e o silêncio da cliente encerra contactos que ainda poderiam ser esclarecidos.","base_instavel":"Algumas conversas avançam bem, mas o acompanhamento depende da confiança ou da disponibilidade do momento. O processo muda e torna difícil perceber onde as clientes desistem.","perde_oportunidades":"A loja orienta a maior parte das conversas e acompanha interesses concretos. Ainda existem oportunidades perdidas depois do preço, antes do pagamento ou após a entrega.","area_forte":"Existe um passo seguinte claro, acompanhamento respeitoso e contacto depois da venda. O próximo ganho está em adaptar respostas às objeções mais frequentes e melhorar a recompra.","area_consolidada":"O interesse é conduzido sem pressão, os contactos não desaparecem por falta de seguimento e a relação continua depois da entrega."},"ritmo_campanhas":{"bloqueio_direto":"A loja decide e divulga demasiado perto da data de venda. Conteúdo, materiais, produção e entrega entram em conflito, e boas oportunidades perdem-se porque a preparação começa quando a cliente já está a procurar.","base_instavel":"Existem ideias e algumas datas planeadas, mas o trabalho continua dependente da urgência. As campanhas são preparadas sem tempo para testar, corrigir ou repetir aquilo que funcionou.","perde_oportunidades":"A loja planeia produtos e datas com alguma antecedência. Falta ligar melhor divulgação, capacidade e revisão para transformar campanhas isoladas num sistema mais previsível.","area_forte":"Produtos, comunicação, produção e entrega são preparados de forma coordenada. O próximo ganho está em comparar campanhas e usar resultados anteriores para decidir investimento e repetição.","area_consolidada":"A loja trabalha com direção, antecedência e revisão. As campanhas respeitam a capacidade real e cada ciclo deixa informação útil para o seguinte."}},"questionFeedback":{"q01":{"reading":"Ainda não existe uma descrição útil de quem compra e de quem utiliza ou recebe o produto. Isso obriga cada publicação a começar do zero.","action":"Revê as últimas dez perguntas ou encomendas e regista quem comprou, para quem era e o que essa pessoa precisava de resolver."},"q02":{"reading":"Os produtos aparecem sem momentos de compra claros. A cliente pode gostar, mas não reconhece quando ou por que razão deveria avançar.","action":"Escolhe três produtos e completa a frase: “Este produto costuma ser procurado quando...”. Usa situações reais, não descrições gerais."},"q03":{"reading":"As decisões continuam apoiadas sobretudo na intuição. Perguntas, recusas e pedidos reais ainda não estão a ser usados para corrigir a loja.","action":"Durante 14 dias, guarda as palavras usadas pelas clientes nas perguntas, dúvidas e recusas. No final, procura repetições."},"q04":{"reading":"A primeira impressão da página não esclarece suficientemente o que se vende e para que tipo de compra. A cliente precisa de investigar antes de perceber se encontrou o lugar certo.","action":"Mostra a página durante cinco segundos a alguém que não conhece a loja e pergunta apenas: “O que achas que esta loja vende e para quem?”. Não expliques antes."},"q05":{"reading":"A diferença da loja está apoiada em palavras que quase qualquer concorrente poderia usar, como qualidade, carinho ou feito à mão.","action":"Compara a tua oferta com três alternativas e escreve uma diferença verificável: escolha, processo, especialização, prazo, combinação, acompanhamento ou resultado."},"q06":{"reading":"Os pedidos recebidos não correspondem ao tipo de produto ou cliente que a loja quer atrair. A comunicação está a chamar atenção, mas não necessariamente a atenção certa.","action":"Compara os últimos dez pedidos com aquilo que queres vender. Marca quais estão alinhados, quais estão próximos e quais não deveriam continuar a ocupar espaço."},"q07":{"reading":"Não existe uma prioridade comercial para os próximos 30 dias. Qualquer produto pode ocupar o centro da loja, mesmo sem procura, margem ou capacidade para o vender bem.","action":"Escolhe no máximo três prioridades usando quatro critérios: procura, margem, facilidade de explicar e capacidade real de produzir ou entregar."},"q08":{"reading":"A cliente encontra várias opções, mas não percebe qual deve escolher primeiro nem o que muda entre elas.","action":"Coloca as opções lado a lado e responde, para cada uma: para quem é, o que inclui, quanto tempo exige e quando deve ser escolhida."},"q09":{"reading":"O destaque dos produtos depende mais do gosto pessoal ou da novidade do que dos sinais comerciais da loja.","action":"Cria uma tabela com encomendas, perguntas, margem, tempo de produção e capacidade dos últimos 90 dias. Compara antes de decidir o que promover."},"q10":{"reading":"O preço pode não estar a cobrir todos os custos ou o tempo necessário para vender e entregar. Uma venda pode entrar sem deixar margem suficiente.","action":"Recalcula um produto frequente incluindo produto ou materiais, tempo, embalagem, taxas, custos de venda, falhas e margem."},"q11":{"reading":"O preço aparece sem informação suficiente para a cliente perceber o que está incluído e por que razão aquela opção custa esse valor.","action":"Escolhe uma oferta e apresenta, junto ao preço, o que inclui, para quem foi pensada, o que pode ser escolhido e o que reduz risco ou trabalho para a cliente."},"q12":{"reading":"A conversa sobre preço não conduz a uma decisão. A cliente recebe o número, mas não recebe ajuda para escolher nem um passo seguinte claro.","action":"Prepara uma resposta com quatro partes: necessidade, opção indicada, condições e próxima ação. Testa-a sem acrescentar desconto."},"q13":{"reading":"As primeiras imagens ou frases não ajudam a cliente a perceber rapidamente se aquele conteúdo lhe diz respeito.","action":"Reescreve a abertura de três publicações usando uma pessoa, um momento de compra e um detalhe específico do produto."},"q14":{"reading":"O produto aparece isolado, sem escala, utilização, processo, comparação ou resultado. A cliente vê o objeto, mas tem de imaginar o resto.","action":"Cria cinco imagens do mesmo produto: utilização, tamanho, detalhe, processo e resultado final."},"q15":{"reading":"Os conteúdos não têm uma função definida ou os resultados não são revistos. Torna-se difícil perceber o que deve ser repetido.","action":"Revê as últimas dez publicações. Regista o objetivo de cada uma e os sinais recebidos: respostas, partilhas, cliques, pedidos e encomendas."},"q16":{"reading":"A loja não tem uma forma planeada de aparecer perante pessoas novas. O crescimento fica limitado ao público atual e às recomendações ocasionais.","action":"Escolhe apenas uma fonte de descoberta adequada ao teu ramo e define uma ação semanal durante quatro semanas."},"q17":{"reading":"A divulgação é usada apenas quando as vendas param. A mensagem e a oferta mudam antes de existir repetição suficiente para avaliar.","action":"Mantém a mesma oferta e a mesma fonte de divulgação durante quatro semanas, corrigindo apenas aquilo que os sinais mostrarem."},"q18":{"reading":"A loja recebe visitas ou pedidos, mas não sabe de onde vieram. Sem essa informação, é fácil repetir ações que não trazem clientes adequados.","action":"Pergunta “Como conheceste a loja?” em cada novo pedido e regista a resposta numa lista simples."},"q19":{"reading":"Existem poucas imagens recentes que permitam observar acabamento, tamanho, utilização e resultado. A cliente não consegue confirmar aquilo que a descrição promete.","action":"Fotografa um produto real em cinco vistas: conjunto, detalhe, escala, utilização e resultado entregue."},"q20":{"reading":"As opiniões aparecem sem indicar produto, situação ou resultado. O elogio existe, mas não ajuda outra pessoa a reduzir uma dúvida concreta.","action":"Pede a três clientes que indiquem o que compraram, para que situação, por que escolheram e como correu."},"q21":{"reading":"Prazos, etapas, aprovações e condições não estão suficientemente claros antes do pagamento. O risco percebido aumenta.","action":"Cria um bloco “Antes de encomendar” com prazo, etapas, confirmação, entrega e procedimento em caso de alteração ou erro."},"q22":{"reading":"A cliente não encontra uma instrução simples para começar a encomenda. O interesse fica dependente de ter iniciativa para perguntar.","action":"Escreve uma frase com o canal, a informação inicial e o que acontece depois: “Para encomendar, envia... Eu confirmo...”."},"q23":{"reading":"Faltam informações que a cliente precisa de comparar ou preparar antes de entrar em contacto.","action":"Simula uma encomenda como cliente e regista todas as perguntas necessárias sobre preço, opções, tamanho, quantidade, prazo, personalização e entrega."},"q24":{"reading":"Cada encomenda é recebida de maneira diferente e aumenta o risco de dados esquecidos, alterações ou erros.","action":"Cria uma lista de confirmação com todos os dados obrigatórios e usa-a antes de aceitar o pagamento ou iniciar o trabalho."},"q25":{"reading":"A resposta informa, mas não ajuda a cliente a escolher nem indica uma ação para avançar.","action":"Prepara uma pergunta útil para cada oferta principal, ligada a prazo, utilização, quantidade, tamanho ou personalização."},"q26":{"reading":"Os contactos que ficam em silêncio são abandonados sem confirmação. A loja não distingue falta de interesse de dúvida, distração ou necessidade de tempo.","action":"Cria uma única mensagem de acompanhamento, enviada no prazo adequado, que retome o produto e ofereça ajuda concreta sem pressionar."},"q27":{"reading":"A relação termina na entrega. Perdem-se opiniões, recomendações e novas compras que poderiam nascer de uma experiência positiva.","action":"Prepara uma mensagem pós-entrega com três partes: confirmação, pergunta sobre a experiência e pedido de opinião ou fotografia."},"q28":{"reading":"Não existe uma direção comercial para os próximos 30 dias. As publicações e os produtos competem entre si sem um objetivo comum.","action":"Define um produto prioritário, um objetivo, quatro conteúdos e uma data de divulgação para os próximos 30 dias."},"q29":{"reading":"A campanha começa sem tempo suficiente para imagens, materiais, stock, produção ou entrega. A urgência reduz qualidade e capacidade de venda.","action":"Parte da data de entrega e recua no calendário: último pedido, início da divulgação, produção de conteúdo e preparação de materiais."},"q30":{"reading":"O mês ou campanha termina sem uma revisão. Erros e acertos ficam dependentes da memória e não melhoram o plano seguinte.","action":"Reserva 15 minutos para registar cinco dados: alcance útil, perguntas, encomendas, produtos parados e motivo das desistências conhecidas."}},"branchReadings":{"personalizados":{"cliente_comprador":{"reading":"Quem paga nem sempre é quem recebe ou utiliza o produto. Uma caneca para professora, um body para bebé e uma placa para empresa podem ser produzidos pela mesma loja, mas nascem de pessoas, motivos e prazos completamente diferentes. Quando tudo é tratado apenas como “personalizados”, a comunicação perde a situação que faz a cliente reconhecer a compra.","action":"Revê as dez encomendas mais recentes e regista quatro dados: quem comprou, para quem era, qual era a ocasião e que detalhe precisava de ser personalizado.","deeper":"Perfis de comprador e destinatário, ocasiões de compra, antecedência e produtos que funcionam como entrada em cada situação."},"posicionamento":{"reading":"Sublimação, vinil, bordado ou gravação explicam como o produto é feito, mas não explicam por que razão a cliente deve escolher aquela loja. A diferença pode estar na especialização numa ocasião, no estilo gráfico, na ajuda a escolher, no processo de aprovação, no acabamento ou no cumprimento de prazos.","action":"Retira por momentos o nome da técnica da apresentação da loja e escreve uma frase que explique que tipo de presente ou encomenda resolves melhor do que as alternativas.","deeper":"Formas de posicionar uma loja de personalizados sem depender de “feito com amor”, preço baixo ou listas intermináveis de produtos."},"oferta_principal":{"reading":"Cada produto pode ter cores, tamanhos, tipos de letra, imagens, frases e materiais diferentes. Quando todas as combinações aparecem ao mesmo nível, a cliente não sabe por onde começar e a lojista passa demasiado tempo a explicar opções que raramente são escolhidas.","action":"Escolhe três encomendas prioritárias e cria para cada uma uma opção-base, uma escolha intermédia e uma opção mais completa. Limita as variantes visíveis às que consegues produzir bem.","deeper":"Menus de personalização, produtos de entrada, conjuntos, limites de escolha e organização por destinatário ou ocasião."},"preco_valor":{"reading":"A cliente vê o objeto final e pode compará-lo com um produto sem personalização. Ficam escondidos o desenho, a preparação do ficheiro, a comunicação, a aprovação, o teste, o risco de erro, a embalagem e o tempo reservado para produzir uma única peça.","action":"Escolhe uma encomenda frequente e separa o preço em cinco blocos internos: produto-base, personalização, preparação, risco ou desperdício e entrega. Depois mostra à cliente o que está incluído, sem expor a conta interna.","deeper":"Custos próprios da personalização, alterações, urgências, quantidades, mínimos, aprovações e formas de apresentar valor antes da comparação pelo objeto."},"conteudo_hooks":{"reading":"Fotografar apenas a peça pronta faz desaparecer a transformação. A cliente precisa de imaginar o nome, a fotografia, a frase ou o desenho aplicado à pessoa e ao momento que tem em mente. O conteúdo ganha força quando mostra escolha, preparação, antes e depois, detalhe e reação de quem recebe.","action":"Para um produto prioritário, cria uma sequência com cinco momentos: situação de compra, produto-base, escolha da personalização, resultado final e entrega ou utilização.","deeper":"Ângulos de conteúdo por ocasião, destinatário, técnica e nível de personalização, sem repetir apenas fotografias de nomes diferentes."},"alcance_divulgacao":{"reading":"A procura surge muitas vezes antes de datas, momentos familiares, início das aulas, festas ou ações empresariais. Divulgar apenas para os seguidores atuais e já perto do prazo reduz o público e obriga a competir pela urgência.","action":"Escolhe uma ocasião com procura nas próximas seis semanas e identifica onde estão as pessoas que compram para esse momento: comunidades locais, escolas, empresas, profissionais de eventos ou negócios complementares.","deeper":"Calendário de ocasiões, parcerias, encomendas empresariais, divulgação local e ações que respeitam a antecedência necessária."},"prova_confianca":{"reading":"Um mockup pode ajudar a escolher, mas não prova acabamento, cor, tamanho, alinhamento ou qualidade da aplicação. A cliente também precisa de confiar que os dados serão confirmados, que verá o que for necessário antes da produção e que a peça chegará dentro do prazo.","action":"Reúne para um produto uma fotografia geral, dois detalhes reais, uma imagem de escala, uma aprovação e uma opinião que mencione resultado e prazo.","deeper":"Provas por técnica, processo de aprovação, diferenças entre simulação e resultado real, proteção de dados e comunicação de prazos."},"caminho_compra":{"reading":"Uma encomenda pode exigir nome, data, frase, fotografia, cor, tamanho, tipo de letra, quantidade, prazo e entrega. Quando estes dados chegam em mensagens separadas, aumentam o tempo, as alterações e o risco de produzir com informação errada.","action":"Cria uma ficha única para o produto mais vendido com todos os dados obrigatórios e uma confirmação final que a cliente deve aprovar antes da produção.","deeper":"Formulários de pedido, recolha de ficheiros, aprovações, alterações, sinais, pagamentos e confirmação da encomenda."},"fecho_acompanhamento":{"reading":"Perguntas como “quanto custa com nome?” raramente contêm informação suficiente. Responder apenas com preço deixa por resolver destinatário, quantidade, data e tipo de personalização. Quando a conversa para, o prazo da ocasião continua a aproximar-se.","action":"Depois do preço inicial, faz uma pergunta que reduza a escolha: “Para que data precisas e para quem é?”. Usa a resposta para indicar a opção e o limite de encomenda.","deeper":"Respostas por tipo de pedido, seguimento antes do fecho de agenda, confirmação, pós-entrega e recompra em novas ocasiões."},"ritmo_campanhas":{"reading":"A campanha pode vender mais do que a capacidade disponível. Sem datas-limite, stock de produtos-base, materiais e horários de produção, a divulgação cria urgências, atrasos e encomendas que já não deveriam ser aceites.","action":"Para a próxima data, define cinco momentos: compra de materiais, produção das amostras, início da divulgação, último dia para encomendar e dias reservados à produção e entrega.","deeper":"Calendário por ocasião, vagas de produção, datas de corte, preparação de amostras, stock-base e gestão de urgências."}},"artesanato":{"cliente_comprador":{"reading":"Uma peça artesanal pode ser comprada para uso próprio, presente, decoração, coleção ou memória. Dizer apenas que a cliente “valoriza o artesanal” não explica o que a leva a escolher uma vela, uma mala em croché, uma peça de cerâmica ou uma joia naquele momento.","action":"Escolhe os cinco produtos mais pedidos e regista se foram comprados para uso, presente, casa, ocasião ou coleção. Acrescenta o motivo referido pela cliente.","deeper":"Situações de compra, diferença entre compradora e destinatária, procura por materiais, estilo, significado e exclusividade."},"posicionamento":{"reading":"“Feito à mão” descreve milhares de lojas e não mostra estilo, material, técnica, utilização ou tipo de peça. A cliente precisa de perceber que universo encontra ali e aquilo que não encontraria facilmente numa produção industrial ou noutra artesã.","action":"Completa a frase: “As minhas peças são escolhidas por pessoas que procuram ___, porque eu trabalho ___ de forma ___”. Preenche com elementos que possam ser vistos ou confirmados.","deeper":"Autoria, assinatura visual, especialização por material ou utilização e apresentação da diferença sem linguagem vazia."},"oferta_principal":{"reading":"A vontade de experimentar novas técnicas pode criar uma loja cheia de peças sem relação comercial. Produtos únicos, coleções pequenas e peças repetíveis precisam de papéis diferentes para que a divulgação não prometa aquilo que a produção não consegue repetir.","action":"Separa a oferta em três grupos: peças que consegues repetir, peças únicas e experiências ou testes. Escolhe qual grupo deve sustentar as vendas dos próximos 30 dias.","deeper":"Coleções, séries limitadas, peças únicas, produtos permanentes, encomendas especiais e limites de produção."},"preco_valor":{"reading":"O tempo manual, os testes, a secagem, o acabamento, o desperdício e a aprendizagem técnica desaparecem quando a peça é comparada apenas pelo tamanho ou matéria-prima. Ao mesmo tempo, dizer quantas horas demorou não basta para criar valor para a cliente.","action":"Recalcula uma peça incluindo preparação, produção, acabamento, desperdício e embalagem. Depois escolhe três detalhes que a cliente consegue observar e que justificam a diferença no resultado.","deeper":"Cálculo de tempo, lotes, perdas, materiais, exclusividade e comunicação de valor sem transformar a descrição numa aula técnica."},"conteudo_hooks":{"reading":"Mostrar apenas a bancada ou apenas a peça pronta deixa metade da história de fora. A cliente precisa de ver textura, escala, utilização, transformação e detalhes que não seriam percebidos numa fotografia distante.","action":"Cria uma sequência para uma peça: material inicial, gesto ou etapa decisiva, detalhe de acabamento, escala na mão ou no espaço e utilização final.","deeper":"Conteúdo de processo com intenção comercial, cuidado da peça, materiais, autoria, utilização e construção de coleções."},"alcance_divulgacao":{"reading":"O público adequado pode estar em mercados, lojas de autor, espaços locais, comunidades de decoração, presentes ou técnicas específicas. Publicar apenas para o público atual limita a descoberta a pessoas que já conhecem o trabalho.","action":"Escolhe um produto principal e identifica três negócios ou espaços frequentados pela mesma cliente, mas que não vendem o mesmo produto. Prepara uma proposta concreta de colaboração ou exposição.","deeper":"Mercados, lojas parceiras, coleções conjuntas, presentes, imprensa local, encomendas por ocasião e critérios para escolher colaborações."},"prova_confianca":{"reading":"Variações naturais podem ser parte da peça, mas a cliente precisa de distinguir variação de defeito. Materiais, medidas, peso, acabamento, cuidados e resistência devem ser mostrados para reduzir surpresas depois da compra.","action":"Para um produto, reúne medidas, material, variações possíveis, cinco imagens reais e cuidados necessários. Acrescenta uma opinião que mencione utilização ou durabilidade.","deeper":"Fotografias de detalhe, descrição de materiais, variações manuais, conservação, embalagem e prova de utilização real."},"caminho_compra":{"reading":"Uma peça pode estar disponível, ser produzida novamente ou aceitar alterações. Quando a cliente não sabe qual destas situações se aplica, pergunta por opções impossíveis ou espera um prazo que a artesã nunca confirmou.","action":"Identifica cada produto como “disponível”, “feito por encomenda” ou “peça única” e apresenta prazo, alterações permitidas e forma de entrega.","deeper":"Stock artesanal, encomendas especiais, repetição de peças, variações, reservas, sinais e confirmação de medidas ou materiais."},"fecho_acompanhamento":{"reading":"A cliente pode hesitar por preço, prazo, cuidado ou receio de a peça real ser diferente da fotografia. Uma resposta defensiva sobre o trabalho manual não resolve a dúvida e pode encerrar a conversa.","action":"Quando surgir uma objeção, confirma primeiro qual é a dúvida: orçamento, data, utilização, manutenção ou diferença entre peças. Responde apenas depois de perceber o motivo.","deeper":"Respostas a objeções, reservas, encomendas especiais, acompanhamento durante a produção, cuidados pós-venda e novas coleções."},"ritmo_campanhas":{"reading":"Algumas técnicas exigem secagem, cura, montagem, produção por lotes ou compra antecipada de materiais. Uma campanha lançada sem essa conta pode vender peças que já não cabem no tempo disponível.","action":"Calcula a capacidade semanal real do produto escolhido e desconta tempo de acabamento, fotografia, embalagem e imprevistos antes de definir quantidades para divulgação.","deeper":"Produção por lotes, séries limitadas, compra de materiais, calendário sazonal, capacidade e datas de fecho de encomendas."}},"moda":{"cliente_comprador":{"reading":"Idade e género não chegam para orientar uma coleção. A mesma peça pode ser procurada para trabalho, cerimónia, dia a dia, presente, conforto, afirmação de estilo ou necessidade de um tamanho específico. Sem perceber a situação, a loja mostra roupa sem ajudar a cliente a imaginar-se a usá-la.","action":"Revê as últimas dez vendas e regista ocasião, dificuldade de escolha, tamanho, peça comprada e motivo referido pela cliente.","deeper":"Situações de uso, necessidades de tamanho e corte, compradora de presente, estilo e critérios que orientam a escolha."},"posicionamento":{"reading":"“Moda feminina” ou “peças escolhidas com carinho” não permite perceber estilo, corpo, ocasião, faixa de preço ou tipo de seleção. Uma boutique, uma marca de produção própria e uma criadora de acessórios precisam de diferenças visíveis e não apenas de um nome bonito.","action":"Escolhe cinco peças que representam melhor a loja e identifica o que têm em comum no estilo, utilização, corte, material e cliente. Usa essa repetição para escrever a direção da marca.","deeper":"Curadoria, assinatura de coleção, especialização por uso ou tamanho e coerência entre imagem, oferta e cliente."},"oferta_principal":{"reading":"Tamanhos, cores, modelos, coleções e acessórios podem transformar a página num catálogo sem prioridade. Quando stock antigo, novidades e peças principais recebem o mesmo destaque, a cliente não sabe o que representa a loja nem o que deve experimentar primeiro.","action":"Escolhe uma peça principal, duas combinações e um complemento. Mostra-os como um pequeno percurso de escolha, com stock e tamanhos reais.","deeper":"Peças principais, cápsulas, conjuntos, complementos, novidades, reposições e saída de stock sem desvalorizar toda a loja."},"preco_valor":{"reading":"A comparação pelo preço ignora tecido, corte, acabamento, origem, conforto, durabilidade, produção limitada e ajuda na escolha. Quando esses elementos não são visíveis, uma peça própria pode parecer equivalente a uma alternativa produzida em massa.","action":"Escolhe uma peça e mostra quatro provas junto ao preço: material, detalhe de acabamento, comportamento no corpo ou utilização e orientação de tamanho.","deeper":"Custos de produção ou revenda, margem, stock, saldos, conjuntos, valor do corte e comunicação sem atacar marcas mais baratas."},"conteudo_hooks":{"reading":"Uma fotografia frontal não responde como a peça assenta, se tem movimento, como combina ou que tamanho está a ser usado. A cliente precisa de se imaginar na roupa e reduzir o medo de escolher mal.","action":"Para uma peça, cria cinco conteúdos: frente e costas, movimento, detalhe do material, medidas ou tamanho usado e duas formas de combinar.","deeper":"Conteúdo por ocasião, corpo, combinação, coleção, detalhe, prova de tamanho e diferença entre mostrar e ajudar a escolher."},"alcance_divulgacao":{"reading":"A descoberta pode nascer de pessoas que usam o produto, negócios locais, profissionais de imagem, eventos ou comunidades ligadas ao estilo. Enviar peças sem critério ou fazer uma colaboração isolada raramente cria um canal repetível.","action":"Escolhe uma peça e procura três pessoas ou negócios cujo público tenha a situação de uso certa. Propõe um conteúdo ou combinação concreta, não apenas “uma parceria”.","deeper":"Colaborações, provas reais, lançamentos, eventos, divulgação local e critérios para escolher pessoas que atraem clientes adequadas."},"prova_confianca":{"reading":"A maior dúvida pode estar no tamanho, transparência, textura, elasticidade, fecho, peso, cor real ou possibilidade de troca. Sem imagens e condições claras, a cliente adia a compra para evitar escolher mal.","action":"Completa uma ficha de produto com medidas da peça, tamanho usado na imagem, material, elasticidade, detalhes de fecho, cuidados e condições de troca.","deeper":"Guias de tamanho, prova em corpos diferentes, materiais, cores, trocas, stock real e opiniões ligadas ao ajuste e utilização."},"caminho_compra":{"reading":"A cliente precisa de confirmar tamanho, stock, cor, entrega e troca antes de avançar. Quando estas respostas estão espalhadas por publicações e mensagens, a compra exige mais segurança e tempo do que deveria.","action":"Simula a compra de uma peça e coloca num único local tamanho, medidas, cor, stock, preço, entrega, troca e ação para encomendar.","deeper":"Escolha de tamanho, reservas, stock, encomenda de produção própria, portes, trocas e confirmação da compra."},"fecho_acompanhamento":{"reading":"“Tem no meu tamanho?” pode ser uma dúvida sobre medidas, corte ou confiança, não apenas disponibilidade. Responder “sim” ou “não” sem ajudar a comparar pode terminar a conversa antes de existir uma alternativa.","action":"Quando perguntarem por tamanho, pede uma medida ou uma peça de referência e explica como o modelo assenta. Se não existir stock, indica uma alternativa concreta ou possibilidade real de reposição.","deeper":"Ajuda na escolha, alternativas, reservas, reposições, carrinhos abandonados, trocas, pós-venda e combinações futuras."},"ritmo_campanhas":{"reading":"Uma coleção exige escolha, encomenda ou produção, fotografia, organização de stock, tamanhos e combinações. Lançar tudo no mesmo dia sem preparação reduz o tempo para criar desejo e aumenta erros de disponibilidade.","action":"Para a próxima coleção, separa calendário de produto, fotografia, apresentação, acesso antecipado, lançamento, reposição e saída das peças com menor procura.","deeper":"Cápsulas, coleções, estações, stock, reposições, saldos, datas de fotografia e leitura de vendas por tamanho e modelo."}},"papelaria":{"cliente_comprador":{"reading":"Quem compra pode não ser quem utiliza. Etiquetas são escolhidas por familiares, convites por quem organiza o evento, agendas por quem quer mudar uma rotina e ficheiros digitais por quem precisa de imprimir ou editar. O produto só ganha força quando aparece ligado à tarefa ou ao momento real.","action":"Para os cinco produtos principais, regista quem compra, quem usa, em que momento começa a procurar e que tarefa quer facilitar.","deeper":"Organização, escola, presente, evento, memória, trabalho e diferenças entre produto físico, imprimível e editável."},"posicionamento":{"reading":"“Papelaria bonita e personalizada” não mostra utilidade, estilo, formato ou situação. Uma encadernadora, uma ilustradora e uma criadora de templates podem partilhar materiais visuais e, mesmo assim, resolver compras completamente diferentes.","action":"Escolhe os três produtos que melhor representam a loja e escreve para cada um a utilização, o estilo e a transformação concreta que entrega.","deeper":"Direção visual ligada à função, especialização por momento, diferença entre decoração e utilidade e apresentação de produtos digitais."},"oferta_principal":{"reading":"Formatos, tamanhos, tipos de papel, quantidades, capas, páginas, versões físicas e digitais podem criar escolhas excessivas. A cliente precisa de um ponto de entrada antes de receber todas as possibilidades.","action":"Organiza uma oferta em três níveis: essencial, conjunto recomendado e versão completa. Em cada nível, explica utilização e diferença, não apenas quantidade.","deeper":"Conjuntos, formatos, coleções, versões digitais, personalização, produtos complementares e limites de escolha."},"preco_valor":{"reading":"O preço pode esconder desenho, revisão, preparação do ficheiro, impressão, papel, corte, encadernação, embalagem, licença de uso e apoio à cliente. Num produto digital, a ausência de material físico não significa ausência de trabalho ou valor.","action":"Escolhe um produto e separa internamente criação, preparação, produção ou plataforma, personalização, apoio e licença ou condições de utilização.","deeper":"Custos físicos e digitais, revisões, quantidades, licenças, impressão, conjuntos e comunicação de valor sem justificar tudo pelo número de horas."},"conteudo_hooks":{"reading":"Mostrar apenas a capa ou uma imagem reduzida não permite perceber páginas interiores, escala, textura, utilização ou resultado depois de imprimir. A cliente precisa de ver o produto em ação e não apenas o ficheiro ou objeto fechado.","action":"Mostra um produto em cinco momentos: visão geral, interior, detalhe, escala ou formato e utilização real antes e depois.","deeper":"Demonstrações, organização, páginas interiores, impressão, montagem, uso digital, personalização e conteúdo por época."},"alcance_divulgacao":{"reading":"A procura acompanha calendários escolares, casamentos, organização anual, presentes e necessidades profissionais. Também pode nascer de parcerias com escolas, espaços de eventos, fotógrafos, organizadores ou outras criadoras.","action":"Escolhe uma utilização com procura próxima e identifica três lugares ou profissionais que encontram essa cliente antes de ela procurar o produto.","deeper":"Calendário escolar e de eventos, pesquisa por utilização, parcerias, produtos para empresas e divulgação de ficheiros digitais."},"prova_confianca":{"reading":"A cliente pode ter dúvidas sobre cor, qualidade de impressão, gramagem, acabamento, quantidade de páginas, compatibilidade, edição, tamanho do ficheiro ou resultado depois de imprimir. Uma simulação bonita não resolve essas dúvidas.","action":"Cria uma ficha com fotografias reais ou capturas completas, dimensões, materiais ou formato de ficheiro, conteúdo incluído e resultado de utilização.","deeper":"Amostras, provas de impressão, compatibilidade, instruções, direitos de utilização, revisões e diferenças entre simulação e produto final."},"caminho_compra":{"reading":"Convites, etiquetas e ilustrações podem exigir nomes, textos, datas, quantidades, medidas, fotografias, ficheiros e aprovações. Produtos digitais podem exigir formato, programa, email e instruções de acesso. Dados incompletos atrasam revisão e entrega.","action":"Cria uma lista única por produto com tudo o que a cliente deve enviar, o número de revisões, o formato entregue e o prazo que começa depois da confirmação.","deeper":"Recolha de textos e ficheiros, provas, revisões, quantidades, impressão, downloads, acesso e confirmação final."},"fecho_acompanhamento":{"reading":"“Quanto custa um convite?” não indica quantidade, formato, impressão, personalização ou prazo. Sem perguntas orientadas, a resposta pode parecer cara ou inadequada porque compara produtos diferentes.","action":"Antes de fechar valor, confirma utilização, quantidade, formato, data e se a cliente precisa apenas do design ou também da produção.","deeper":"Pedidos de orçamento, revisões, aprovação, seguimento, entrega de ficheiros, apoio de utilização e recompra em novas épocas."},"ritmo_campanhas":{"reading":"A procura começa antes do regresso às aulas, planeamento anual, festas ou eventos. Fotografar, imprimir, montar e enviar também exige tempo. Apresentar o produto quando a data chegou reduz a janela de compra.","action":"Parte da data de utilização e define último dia de encomenda, prazo de aprovação, produção, envio, criação de amostras e início da divulgação.","deeper":"Calendários escolares e de eventos, produção por quantidades, lançamentos digitais, revisões, datas de corte e reaproveitamento de campanhas."}},"eventos":{"cliente_comprador":{"reading":"Quem encomenda está a organizar um momento para outras pessoas. Pode procurar emoção, coerência visual, facilidade, controlo do orçamento ou segurança de que tudo chegará a tempo. A compra muda entre casamento, aniversário, batizado, evento empresarial ou festa infantil.","action":"Revê as últimas dez encomendas e regista tipo de evento, pessoa que decidiu, número de convidados, maior preocupação e motivo usado para escolher.","deeper":"Organizadores, destinatários, convidados, tipos de evento, prioridades emocionais e práticas e antecedência de decisão."},"posicionamento":{"reading":"“Tornamos o teu dia especial” poderia pertencer a quase qualquer negócio de eventos. A cliente precisa de perceber o tipo de celebração, estilo, escala, peças fornecidas e nível de acompanhamento em que a loja é realmente forte.","action":"Escolhe três eventos que representam o trabalho que queres repetir e identifica o que partilham em estilo, dimensão, cliente, orçamento e tipo de solução.","deeper":"Especialização por evento, estilo, conjunto, quantidade, serviço associado e diferença entre produto isolado e solução coordenada."},"oferta_principal":{"reading":"Convites, lembranças, toppers, placas, decoração e elementos de mesa podem ser vendidos isoladamente ou em conjunto. Sem pacotes e limites claros, cada orçamento começa do zero e a cliente não consegue comparar níveis de solução.","action":"Cria três entradas: elemento principal, conjunto coordenado e solução mais completa. Define quantidade mínima, o que inclui e o que continua opcional.","deeper":"Pacotes, quantidades, complementos, aluguer ou montagem quando aplicável, mínimos e limites de personalização."},"preco_valor":{"reading":"O valor pode incluir desenho, preparação, amostra, montagem, unidade, quantidade, transporte, instalação, desmontagem e urgência. Um orçamento com apenas um total impede a cliente de perceber o trabalho e comparar propostas equivalentes.","action":"Organiza internamente um orçamento por preparação, produção, quantidade, personalização, logística e urgência. Na apresentação, mostra claramente o que está incluído e o que é opcional.","deeper":"Mínimos, escalões de quantidade, sinal, alterações, deslocação, montagem, urgências e apresentação de propostas."},"conteudo_hooks":{"reading":"Uma lembrança isolada sobre fundo neutro não mostra quantidade, conjunto, escala nem efeito na celebração. A cliente precisa de imaginar a mesa, o espaço, a entrega aos convidados e a ligação entre os elementos.","action":"Para um evento real, mostra necessidade inicial, escolha do tema, preparação, conjunto montado e detalhe entregue ao convidado.","deeper":"Histórias de eventos, conjuntos, antes e depois, quantidades, montagem, reação e conteúdo que respeita autorização e privacidade."},"alcance_divulgacao":{"reading":"A cliente passa por espaços, fotógrafos, organizadores, lojas de cerimónia, pastelaria, floristas e outros fornecedores antes de fechar todas as escolhas. Uma rede adequada pode apresentar a loja no momento certo da preparação.","action":"Escolhe um tipo de evento e identifica cinco profissionais que trabalham antes ou ao lado da tua encomenda. Prepara uma proposta com um conjunto real, prazos e benefício para as duas partes.","deeper":"Rede de fornecedores, espaços, mostras, eventos empresariais, conteúdos conjuntos e critérios para evitar parcerias sem pedidos adequados."},"prova_confianca":{"reading":"A cliente não pode repetir a data se algo falhar. Precisa de provas de eventos reais, quantidades concluídas, montagem, transporte e cumprimento do prazo, não apenas simulações ou amostras individuais.","action":"Documenta uma encomenda completa com amostra aprovada, produção em quantidade, embalagem ou transporte, resultado no local e opinião que mencione prazo e acompanhamento.","deeper":"Portefólio por evento, provas de quantidade, condições, plano de aprovação, entrega, montagem e resposta a alterações."},"caminho_compra":{"reading":"Data, local, quantidade, tema, cores, nomes, orçamento, montagem, entrega e aprovações precisam de ser recolhidos antes da confirmação. Uma informação esquecida pode obrigar a refazer peças ou alterar toda a logística.","action":"Cria uma ficha de evento com todos os dados, datas de aprovação, valor do sinal, limite de alterações e responsável pela entrega ou receção.","deeper":"Pedido de orçamento, reunião ou briefing, proposta, sinal, amostra, revisões, confirmação de quantidades e entrega."},"fecho_acompanhamento":{"reading":"“Quanto custa para um casamento?” não permite calcular quantidade, peças, data ou nível de serviço. A conversa precisa de confirmar primeiro se existe capacidade e qual é a dimensão real da encomenda.","action":"A primeira resposta deve confirmar data, local, quantidade aproximada e elementos pretendidos. Só depois apresenta o formato de proposta e o prazo para reservar agenda.","deeper":"Qualificação do pedido, proposta, seguimento antes da reserva, alterações, contacto próximo da data e pedido de opinião após o evento."},"ritmo_campanhas":{"reading":"Cada evento tem uma data fixa e várias decisões anteriores. Sem trabalhar para trás, a divulgação pode trazer pedidos quando já não existe tempo para desenho, aprovação, produção e entrega.","action":"Parte da data do evento e recua por entrega, produção, aprovação, proposta, briefing e primeiro contacto. Define a última data segura para aceitar cada tipo de encomenda.","deeper":"Calendário por evento, agenda de produção, reservas, datas de corte, quantidades finais, fornecedores e margem para alterações."}},"pastelaria":{"cliente_comprador":{"reading":"Quem encomenda pode procurar um centro de celebração, uma oferta, uma mesa completa ou pequenas lembranças. A escolha depende de ocasião, número de pessoas, gosto, apresentação, orçamento e segurança na entrega, não apenas de “gostar de doces”.","action":"Revê as últimas dez encomendas e regista ocasião, número de pessoas, produto escolhido, preocupação principal e motivo referido para a compra.","deeper":"Compradora, destinatário, convidados, ocasião, porções, sabores, apresentação e antecedência de decisão."},"posicionamento":{"reading":"“Bolos feitos com amor” não mostra estilo, tipo de celebração, acabamento, sabores ou dimensão das encomendas aceites. A cliente precisa de reconhecer rapidamente se aquela pastelaria corresponde ao resultado que imagina e ao tipo de evento que vai realizar.","action":"Escolhe cinco encomendas que queres voltar a receber e identifica padrão de ocasião, estilo, produto, dimensão e nível de decoração.","deeper":"Especialização por produto, ocasião, estilo, experiência, escala e diferença entre encomenda simples e projeto personalizado."},"oferta_principal":{"reading":"Tamanhos, porções, massas, recheios, coberturas, decorações, caixas e conjuntos podem obrigar a explicar tudo em cada conversa. A cliente precisa de opções orientadas antes de entrar em combinações especiais.","action":"Cria três opções claras para o produto principal, indicando porções ou quantidade, sabores incluídos, nível de decoração e personalizações possíveis.","deeper":"Menus, porções, conjuntos, produtos sazonais, encomendas especiais, extras e limites de alteração."},"preco_valor":{"reading":"Ingredientes, testes, tempo de preparação, decoração, perdas, conservação, embalagem, energia e entrega ficam escondidos quando a cliente compara apenas tamanho ou número de unidades. Uma decoração simples de explicar pode não ser simples de executar.","action":"Recalcula uma encomenda frequente incluindo ingredientes, preparação, decoração, perdas, embalagem, conservação e logística. Apresenta depois o que está incluído e quais escolhas alteram o valor.","deeper":"Porções, quantidades, decoração, urgência, entrega, sinais, extras e apresentação de opções sem desvalorizar o trabalho."},"conteudo_hooks":{"reading":"Uma fotografia exterior não mostra interior, textura, porção, escala, embalagem ou apresentação no evento. A cliente compra também a expectativa de sabor e a segurança de que o produto terá dimensão adequada.","action":"Mostra um produto através de conjunto, escala, interior ou textura, detalhe de decoração, embalagem e utilização no momento da compra.","deeper":"Conteúdo de sabores, porções, processo, decoração, corte, conservação, entrega e ocasiões sazonais."},"alcance_divulgacao":{"reading":"A maior parte da entrega é local e ligada a datas ou eventos. Espaços, decoradores, fotógrafos, lojas de presentes e empresas podem encontrar a mesma cliente antes de ela escolher a pastelaria.","action":"Escolhe um produto e uma ocasião e identifica três negócios locais com público compatível. Apresenta uma proposta concreta com amostra, prazo e forma de encomenda.","deeper":"Descoberta local, eventos, presentes empresariais, parcerias, campanhas sazonais e critérios de raio de entrega."},"prova_confianca":{"reading":"A cliente precisa de confiar na aparência real, quantidade, cumprimento da data, acondicionamento e informações necessárias para consumir ou conservar o produto. Fotografias de referência que não correspondem ao trabalho real aumentam o risco percebido.","action":"Reúne fotografias reais de exterior, interior, escala e embalagem, uma opinião sobre sabor e entrega e informação clara sobre conservação e elementos que a cliente deve comunicar antes da encomenda.","deeper":"Portefólio real, porções, ingredientes e alergénios declarados, conservação, transporte, entrega e condições de alteração."},"caminho_compra":{"reading":"Data, número de pessoas, produto, sabor, decoração, referência, texto, alergias comunicadas, recolha ou entrega e pagamento precisam de estar confirmados. Uma encomenda aceite com dados soltos aumenta o risco de falha.","action":"Cria uma ficha obrigatória e uma confirmação final com data, hora, porções ou quantidade, sabores, decoração, texto, entrega e condições acordadas.","deeper":"Pedido de orçamento, disponibilidade, sinal, confirmação, alterações, recolha, transporte e instruções entregues à cliente."},"fecho_acompanhamento":{"reading":"Antes de discutir todos os detalhes, é necessário confirmar data e capacidade. Uma conversa longa pode terminar sem reserva enquanto a agenda continua a receber outros pedidos.","action":"Começa por confirmar data, quantidade ou porções e tipo de produto. Depois apresenta a opção indicada, o valor de reserva e até quando a disponibilidade pode ser mantida.","deeper":"Qualificação, disponibilidade, proposta, sinal, seguimento, confirmação próxima da entrega e pedido de opinião após consumo."},"ritmo_campanhas":{"reading":"Produção, conservação, compra de ingredientes, decoração e entregas ocupam janelas muito específicas. Uma campanha pode vender mais do que os equipamentos, o espaço ou o tempo permitem preparar com segurança.","action":"Define a capacidade diária e semanal de cada produto, descontando preparação, arrefecimento ou conservação, decoração, embalagem e entrega antes de abrir vagas.","deeper":"Agenda de produção, vagas, compras, campanhas sazonais, datas de corte, entregas, capacidade e gestão de produtos com diferentes tempos de conservação."}},"materiais":{"cliente_comprador":{"reading":"Duas pessoas podem procurar o mesmo material para projetos, máquinas e níveis de experiência diferentes. Saber apenas que a cliente “faz artesanato” não permite orientar quantidade, compatibilidade, dificuldade ou resultado esperado.","action":"Revê as últimas dez vendas e regista técnica da cliente, projeto, nível de experiência, material comprado e dúvida colocada antes da decisão.","deeper":"Criadoras iniciantes e experientes, técnicas, projetos, compras de reposição, produção profissional e critérios de escolha."},"posicionamento":{"reading":"Uma loja com muitas referências pode parecer apenas mais um catálogo. A diferença pode estar na seleção, disponibilidade, conhecimento de compatibilidades, criação de kits, rapidez de reposição ou apoio para evitar a compra errada.","action":"Escolhe a família de materiais em que tens melhor seleção e capacidade de orientar. Explica que projeto ajuda a realizar e que erro de escolha consegues evitar.","deeper":"Especialização por técnica, seleção, apoio, fornecimento profissional, kits e diferença entre quantidade de catálogo e utilidade da oferta."},"oferta_principal":{"reading":"Cores, tamanhos, espessuras, quantidades, marcas, ferramentas e consumíveis podem criar centenas de referências sem uma entrada clara. A cliente iniciante e a profissional não precisam da mesma apresentação.","action":"Organiza uma família de produtos em começar, repor e produzir em quantidade. Cria um kit ou seleção recomendada para cada situação.","deeper":"Famílias de produtos, kits, complementos, consumíveis, reposições, quantidades profissionais e retirada de referências paradas."},"preco_valor":{"reading":"A cliente compara preço por unidade, embalagem ou metro, mas pode não perceber rendimento, consistência, compatibilidade, desperdício evitado e apoio. Um material mais barato pode sair caro quando não funciona no processo utilizado.","action":"Para um material principal, mostra quantidade real, rendimento aproximado quando for possível demonstrar, compatibilidades confirmadas e diferença observável perante a alternativa mais comparada.","deeper":"Preço unitário e por conjunto, rendimento, portes, quantidades, descontos profissionais, qualidade, compatibilidade e custo de uma escolha errada."},"conteudo_hooks":{"reading":"Fotografar a embalagem não mostra cor real, textura, espessura, aplicação, quantidade ou resultado. A cliente precisa de ver o material dentro de um projeto e perceber o que deve usar com ele.","action":"Demonstra um material com escala, aplicação, resultado, comparação e dois complementos necessários para concluir o projeto.","deeper":"Demonstrações, comparações, projetos, compatibilidades, kits, rendimento e conteúdo que ajuda a escolher sem oferecer formação técnica completa."},"alcance_divulgacao":{"reading":"As clientes reúnem-se por técnica, formação, comunidade, oficina e tipo de projeto. Professores, formadores, criadoras experientes e negócios que vendem moldes ou equipamentos podem apresentar a loja a pessoas com necessidade real de material.","action":"Escolhe uma técnica e identifica três pessoas ou comunidades que ensinam ou produzem nessa área. Propõe uma seleção de materiais ligada a um projeto concreto.","deeper":"Comunidades, formadores, fornecimento profissional, projetos conjuntos, reposições e divulgação por técnica em vez de promoções gerais."},"prova_confianca":{"reading":"Cor, lote, medida, espessura, composição e compatibilidade podem alterar o resultado. A cliente precisa de especificações claras e imagens reais, sobretudo quando já teve experiências com materiais inadequados.","action":"Completa a ficha de um produto com medidas, quantidade, variações possíveis, compatibilidades confirmadas, imagens reais e resultado de aplicação.","deeper":"Fichas técnicas comerciais, lotes, cores, medidas, compatibilidades, testes, opiniões de criadoras e limites do apoio prestado."},"caminho_compra":{"reading":"A cliente precisa de escolher referência, variação, quantidade e complementos e confirmar stock, reposição e entrega. Uma referência errada pode tornar inúteis os restantes materiais já comprados.","action":"Para uma família de produtos, cria um percurso com projeto, material principal, variação, quantidade, complementos, stock e prazo de envio.","deeper":"Pesquisa por técnica, filtros, kits, referências, stock, reposições, portes, quantidades e confirmação de compatibilidade."},"fecho_acompanhamento":{"reading":"“Este material serve?” precisa de contexto sobre máquina, técnica, superfície, medida ou resultado. Responder apenas “sim” sem confirmar utilização pode criar devolução, desperdício e perda de confiança.","action":"Prepara perguntas de confirmação para as famílias principais: projeto, equipamento, medida, material onde será aplicado e quantidade necessária.","deeper":"Orientação pré-compra, limites de responsabilidade, alternativas, reposições, avisos de stock e acompanhamento depois da primeira utilização."},"ritmo_campanhas":{"reading":"A procura acompanha épocas escolares, eventos, tendências de técnica, formações e produção sazonal das clientes. Falhas de reposição numa referência principal podem bloquear também a venda de vários complementos.","action":"Identifica as dez referências que sustentam mais projetos e define stock mínimo, prazo de reposição, produtos dependentes e épocas de maior procura.","deeper":"Reposição, stock mínimo, encomendas a fornecedores, sazonalidade, kits, campanhas por projeto e gestão de referências complementares."}}},"branchLabels":{"personalizados":"Personalizados e presentes à medida","artesanato":"Artesanato e peças feitas à mão","moda":"Roupa, moda e acessórios","papelaria":"Papelaria criativa, ilustração e produtos digitais","eventos":"Festas, eventos e lembranças","pastelaria":"Pastelaria criativa e presentes comestíveis","materiais":"Materiais, kits e artigos para outras criadoras"}};

function sosField(name) { return this.getField(name); }
function sosSet(name, value) { var f = sosField.call(this, name); if (f) { f.value = value; } }
function sosHalfUp(value) { return Math.floor(value + 0.5); }
function sosBand(score, bands) {
  for (var i = 0; i < bands.length; i++) {
    if (score >= bands[i].min && score <= bands[i].max) return bands[i];
  }
  return bands[0];
}
function sosFallbackIndex(moduleId) {
  for (var i = 0; i < SOS_DATA.priority.fallback_order.length; i++) {
    if (SOS_DATA.priority.fallback_order[i] == moduleId) return i;
  }
  return 999;
}
function sosReachable(source, target) {
  var pending = (SOS_DATA.priority.dependencies[source] || []).slice(0);
  var visited = {};
  while (pending.length) {
    var current = pending.pop();
    if (current == target) return true;
    if (visited[current]) continue;
    visited[current] = true;
    var next = SOS_DATA.priority.dependencies[current] || [];
    for (var i = 0; i < next.length; i++) pending.push(next[i]);
  }
  return false;
}
function sosSelectLowest(candidates, perceived) {
  var lowest = 999;
  for (var i = 0; i < candidates.length; i++) lowest = Math.min(lowest, candidates[i].exact);
  var tied = [];
  for (var j = 0; j < candidates.length; j++) {
    if (candidates[j].exact - lowest <= SOS_DATA.priority.tie_max_distance) tied.push(candidates[j]);
  }
  var severe = -1;
  for (var k = 0; k < tied.length; k++) severe = Math.max(severe, tied[k].severeCount);
  var severeTied = [];
  for (var l = 0; l < tied.length; l++) if (tied[l].severeCount == severe) severeTied.push(tied[l]);
  var perceivedTied = [];
  for (var m = 0; m < severeTied.length; m++) if (perceived[severeTied[m].id]) perceivedTied.push(severeTied[m]);
  if (perceivedTied.length == 1) return perceivedTied[0];
  var source = perceivedTied.length > 1 ? perceivedTied : severeTied;
  source.sort(function(a, b) { return sosFallbackIndex(a.id) - sosFallbackIndex(b.id); });
  return source[0];
}
function sosSelectPriority(candidates, perceived, excluded) {
  var available = [];
  for (var i = 0; i < candidates.length; i++) if (!excluded[candidates[i].id]) available.push(candidates[i]);
  if (!available.length) return null;
  var selected = sosSelectLowest(available, perceived);
  var reason = "pontuacao_mais_baixa";
  var upstream = [];
  for (var j = 0; j < available.length; j++) {
    var candidate = available[j];
    if (candidate.id != selected.id && sosReachable(candidate.id, selected.id) &&
        Math.abs(candidate.exact - selected.exact) <= SOS_DATA.priority.root_cause_max_distance) {
      upstream.push(candidate);
    }
  }
  if (upstream.length) {
    upstream.sort(function(a, b) { return sosFallbackIndex(a.id) - sosFallbackIndex(b.id); });
    selected = upstream[0];
    reason = "causa_anterior";
  }
  return {id:selected.id, label:selected.label, exact:selected.exact, display:selected.display, band:selected.band, reason:reason, answers:selected.answers, questions:selected.questions};
}
function sosClearResults() {
  var names = ["result_total","result_total_band","result_primary_title","result_primary_base","result_primary_evidence","result_primary_branch","result_primary_action","result_primary_route","result_secondary_title","result_secondary_base","result_secondary_evidence","result_secondary_branch","result_secondary_action"];
  for (var i = 0; i < SOS_DATA.categories.length; i++) names.push("result_cat_" + SOS_DATA.categories[i].id);
  for (var j = 0; j < SOS_DATA.modules.length; j++) names.push("result_mod_" + SOS_DATA.modules[j].id);
  for (var k = 0; k < names.length; k++) sosSet.call(this, names[k], "");
}
function sosRenderPriority(priority, prefix, branchId) {
  if (!priority) {
    sosSet.call(this, prefix + "_title", prefix == "result_primary" ? "Não foi encontrada uma correção urgente" : "Não existe uma segunda prioridade");
    sosSet.call(this, prefix + "_base", prefix == "result_primary" ? "Todos os módulos ficaram acima do limite de prioridade. O resultado deve ser usado para aperfeiçoar, não para inventar um problema." : "Os restantes módulos não justificam uma segunda tarefa imediata.");
    sosSet.call(this, prefix + "_evidence", "");
    sosSet.call(this, prefix + "_branch", "");
    sosSet.call(this, prefix + "_action", "");
    if (prefix == "result_primary") sosSet.call(this, "result_primary_route", "Aperfeiçoamento sem urgência comercial.");
    return;
  }
  var base = SOS_DATA.baseReadings[priority.id][priority.band.id];
  var weak = [];
  for (var i = 0; i < priority.answers.length; i++) {
    if (priority.answers[i] <= SOS_DATA.priority.weak_answer_max) weak.push({value:priority.answers[i], question:priority.questions[i]});
  }
  weak.sort(function(a, b) { if (a.value != b.value) return a.value - b.value; return a.question < b.question ? -1 : 1; });
  var evidence = [];
  for (var j = 0; j < weak.length && j < 2; j++) evidence.push(SOS_DATA.questionFeedback[weak[j].question].reading);
  var action = weak.length ? SOS_DATA.questionFeedback[weak[0].question].action : "Revê as respostas deste módulo e escolhe a primeira falha observável.";
  var branch = SOS_DATA.branchReadings[branchId] ? SOS_DATA.branchReadings[branchId][priority.id] : null;
  var branchText = branch ? branch.reading + "\n\nPrimeira aplicação no ramo: " + branch.action : "Seleciona o ramo principal na ficha da loja para receberes a aplicação direcionada.";
  sosSet.call(this, prefix + "_title", priority.label + " — " + priority.display + "/100");
  sosSet.call(this, prefix + "_base", base);
  sosSet.call(this, prefix + "_evidence", evidence.join("\n\n"));
  sosSet.call(this, prefix + "_branch", branchText);
  sosSet.call(this, prefix + "_action", action);
  if (prefix == "result_primary") {
    var branchLabel = SOS_DATA.branchLabels[branchId] || "Ramo por selecionar";
    sosSet.call(this, "result_primary_route", branchLabel + " + " + priority.label);
  }
}
function sosRunCalculation() {
  var answers = {};
  var missing = [];
  for (var i = 0; i < SOS_DATA.modules.length; i++) {
    var questions = SOS_DATA.modules[i].questions;
    for (var j = 0; j < questions.length; j++) {
      var field = sosField.call(this, questions[j]);
      var value = field ? field.value : "Off";
      if (value === "Off" || value === "") missing.push(questions[j]);
      else answers[questions[j]] = parseInt(value, 10);
    }
  }
  if (missing.length) {
    sosClearResults.call(this);
    sosSet.call(this, "result_status", "Faltam " + missing.length + " respostas. A primeira é " + missing[0].toUpperCase() + ".");
    return;
  }
  var moduleResults = {};
  var eligible = [];
  var totalRaw = 0;
  for (var m = 0; m < SOS_DATA.modules.length; m++) {
    var module = SOS_DATA.modules[m];
    var raw = 0;
    var values = [];
    var weakCount = 0;
    var severeCount = 0;
    for (var q = 0; q < module.questions.length; q++) {
      var answer = answers[module.questions[q]];
      values.push(answer);
      raw += answer;
      totalRaw += answer;
      if (answer <= SOS_DATA.priority.weak_answer_max) weakCount++;
      if (answer <= 1) severeCount++;
    }
    var exact = raw / 12 * 100;
    var display = sosHalfUp(exact);
    var band = sosBand(display, SOS_DATA.moduleBands);
    var result = {id:module.id,label:module.label,exact:exact,display:display,band:band,answers:values,questions:module.questions,weakCount:weakCount,severeCount:severeCount};
    moduleResults[module.id] = result;
    if (exact < SOS_DATA.priority.eligible_below && weakCount >= SOS_DATA.priority.minimum_weak_answers) eligible.push(result);
    sosSet.call(this, "result_mod_" + module.id, display + "/100");
  }
  var totalDisplay = sosHalfUp(totalRaw / 120 * 100);
  var totalBand = sosBand(totalDisplay, SOS_DATA.totalBands);
  sosSet.call(this, "result_total", String(totalDisplay));
  sosSet.call(this, "result_total_band", totalBand.label);
  for (var c = 0; c < SOS_DATA.categories.length; c++) {
    var category = SOS_DATA.categories[c];
    var sum = 0;
    for (var cm = 0; cm < category.modules.length; cm++) sum += moduleResults[category.modules[cm]].exact;
    sosSet.call(this, "result_cat_" + category.id, sosHalfUp(sum / category.modules.length) + "/100");
  }
  var perceived = {};
  for (var p = 0; p < SOS_DATA.modules.length; p++) {
    var perceivedField = sosField.call(this, "difficulty_" + SOS_DATA.modules[p].id);
    if (perceivedField && perceivedField.value != "Off") perceived[SOS_DATA.modules[p].id] = true;
  }
  var primary = sosSelectPriority(eligible, perceived, {});
  var excluded = {};
  if (primary) excluded[primary.id] = true;
  var secondary = sosSelectPriority(eligible, perceived, excluded);
  var branchField = sosField.call(this, "profile_branch");
  var branchId = branchField && branchField.value != "Off" ? branchField.value : "";
  sosRenderPriority.call(this, primary, "result_primary", branchId);
  sosRenderPriority.call(this, secondary, "result_secondary", branchId);
  sosSet.call(this, "result_status", branchId ? "Resultado calculado. Revê a prioridade principal e o passo seguinte." : "Pontuação calculada. Falta selecionar o ramo principal para obter a leitura direcionada.");
}

if (typeof this.getField === "function") sosRunCalculation.call(this);
